INSERT INTO evidence_sources (ref_id, source_type, first_author_last, first_author_first, author_count, author_count_is_complete, is_corporate_primary, pub_year, pub_title, journal_name, volume, issue, article_number, doi, pmid, pmcid, url, jurisdiction, language, lang_detected, tier, evidence_type, scope, verification_status, metadata_quality, doi_resolution_outcome, url_resolution_outcome, verified_by_tool, last_verified_at, prior_expectation, search_queries_used, notes, created_at, created_by_session, updated_at, updated_by_session) VALUES ('REF-00924', 'journal_article', 'Wieczorek', 'Bartosz', 4, 1, 0, 2023, 'Ergonomic guidelines for the design interfaces of additive modules for manual wheelchairs: sagittal plane', 'Scientific Reports', '13', '1', '11993', '10.1038/s41598-023-39085-7', '37491559', 'PMC10368659', 'https://doi.org/10.1038/s41598-023-39085-7', 'PL', 'en', 'en', 3, 'clinical', 'lower_control', 'VERIFIED', 'COMPLETE', 'RESOLVED', 'RESOLVED', 'pubmed', '2026-07-24T06:40:00+00:00', 'Expected anthropometric hand-reach envelopes for manual-wheelchair users to exist mainly as industrial-ergonomics norms (Kozey/Das lineage), not as sagittal-plane control-placement maps; searched to test whether upper-limb reach for control placement is quantified independent of forward/side ADA reach ranges.', 'Consensus: functional reach range envelope adults upper limb impairment wheelchair users forward side reach anthropometry; PubMed verify: Wieczorek ergonomic guidelines additive modules manual wheelchairs sagittal plane', 'Anthropometric/ergonomic primary study (n=10, 50th-pct); total hand-reach area 1269mm x 731mm, comfortable zone 352mm x 649mm. Tier 3 (lower-control primary); relevant to upper-limb control-placement reach. NOT a forward/side ADA reach-range source (those are code-tier ISO 21542).', '2026-07-24T06:40:00+00:00', 'session_2026-07-24-research-matrix-completion', '2026-07-24T06:40:00+00:00', 'session_2026-07-24-research-matrix-completion');
INSERT INTO evidence_sources (ref_id, source_type, first_author_last, first_author_first, author_count, author_count_is_complete, is_corporate_primary, pub_year, pub_title, journal_name, volume, issue, article_number, doi, pmid, pmcid, url, jurisdiction, language, lang_detected, tier, evidence_type, scope, verification_status, metadata_quality, doi_resolution_outcome, url_resolution_outcome, verified_by_tool, last_verified_at, prior_expectation, search_queries_used, notes, created_at, created_by_session, updated_at, updated_by_session) VALUES ('REF-00925', 'journal_article', 'Park', 'Gowun', 5, 1, 0, 2020, 'Creating and Testing a Sensory Well-Being Hub for Adolescents with Developmental Disabilities', 'Journal of Interior Design', '45', '1', NULL, '10.1111/joid.12164', NULL, NULL, 'https://doi.org/10.1111/joid.12164', 'US', 'en', 'en', 3, 'clinical', 'lower_control', 'VERIFIED', 'COMPLETE', 'RESOLVED', 'RESOLVED', 'doi.org', '2026-07-24T06:40:00+00:00', 'Expected sensory-room / multisensory-environment evidence to be dominated by Snoezelen efficacy trials in intellectual disability rather than architectural design-parameter studies of retreat spaces; searched to test whether built-environment design parameters for sensory relief spaces are evidenced.', 'Scholar Gateway: multisensory environments / sensory retreat / quiet rooms for autistic adults in the built environment, design parameters', 'Mixed-methods evaluation of a freestanding sensory well-being hub for adolescents with developmental disabilities (Chicago high school); design-affordance evaluation. Tier 3 (lower-control primary); population NDV/DEV. Relevant to sensory-relief-space-design.', '2026-07-24T06:40:00+00:00', 'session_2026-07-24-research-matrix-completion', '2026-07-24T06:40:00+00:00', 'session_2026-07-24-research-matrix-completion');
